interface TrainingSessionState extends SessionState {
  sessionType: 'quick' | 'full';
  drillQueue: DrillType[];
  currentDrillIndex: number;
  results: DrillResult[];
}

type DrillType = 'number_line' | 'spatial_rotation' | 'math_operations';

// New action to add:
| { type: 'START_TRAINING_SESSION'; payload: { sessionType: 'quick' | 'full'; drillQueue: DrillType[] } }

async function selectDrills(
  weights: TrainingPlanWeights,
  count: number
): Promise<DrillType[]>

interface TrainingPlanWeights {
  numberSense: number;  // 0.0 - 1.0
  spatial: number;
  operations: number;
}

sessions.add({
  timestamp: string;      // ISO 8601
  module: 'training';
  duration: number;       // milliseconds
  completionStatus: 'completed' | 'abandoned' | 'paused';
  confidencePre?: number;
  confidencePost?: number;
})

// Query from Epic 2 assessments table
const assessment = await db.assessments
  .orderBy('timestamp')
  .reverse()
  .first();

// VERIFY Epic 2 implementation includes this field:
assessment.trainingPlanWeights?: {
  numberSense: number;
  spatial: number;
  operations: number;
}

// Fallback if missing:
const defaultWeights = { numberSense: 0.33, spatial: 0.33, operations: 0.34 };
